from dataclasses import dataclass, field, InitVar
from datetime import datetime
import re

@dataclass
class User:
    name: str
    email: str
    age: int
    created_at: datetime = field(default_factory=datetime.utcnow, repr=False)
    is_admin: bool = field(default=False, compare=False)
    tags: list[str] = field(default_factory=list)

    def __post_init__(self):
        # Validation
        if not self.name.strip():
            raise ValueError("Name cannot be empty")
        if not re.match(r'^[\w.-]+@[\w.-]+\.\w+$', self.email):
            raise ValueError(f"Invalid email: {self.email}")
        if self.age < 0 or self.age > 150:
            raise ValueError(f"Invalid age: {self.age}")

        # Normalization
        self.name = self.name.strip().title()
        self.email = self.email.lower()

user = User('  alice  ', 'Alice@Example.COM', 30)
print(user.name)   # 'Alice' (normalized)
print(user.email)  # 'alice@example.com' (lowercased)

# Computed fields with init=False
@dataclass
class Rectangle:
    width: float
    height: float
    area: float = field(init=False)       # Computed, not in __init__
    perimeter: float = field(init=False)  # Computed, not in __init__

    def __post_init__(self):
        self.area = self.width * self.height
        self.perimeter = 2 * (self.width + self.height)

rect = Rectangle(3, 4)  # Only width and height
print(rect.area)       # 12
print(rect.perimeter)  # 14

# InitVar: parameters only for __post_init__, not stored as fields
@dataclass
class PasswordUser:
    username: str
    password: InitVar[str]  # Passed to __post_init__, not stored
    password_hash: str = field(init=False)

    def __post_init__(self, password: str):
        import hashlib
        self.password_hash = hashlib.sha256(password.encode()).hexdigest()

user = PasswordUser('alice', 'secret123')
print(user)  # PasswordUser(username='alice', password_hash='...')
