# Practical: auto-validation from metadata
@dataclass
class ValidatedProduct:
    name: str = field(metadata={'max_length': 100})
    price: float = field(metadata={'min_value': 0})

    def __post_init__(self):
        for f in fields(self):
            value = getattr(self, f.name)
            if 'max_length' in f.metadata and isinstance(value, str):
                if len(value) > f.metadata['max_length']:
                    raise ValueError(f"{f.name} exceeds max length {f.metadata['max_length']}")
            if 'min_value' in f.metadata and isinstance(value, (int, float)):
                if value < f.metadata['min_value']:
                    raise ValueError(f"{f.name} must be >= {f.metadata['min_value']}")

