from typing import Self

# Self type for fluent interfaces / builder pattern
class QueryBuilder:
    def __init__(self):
        self._table = ''
        self._conditions = []
        self._limit = None

    def table(self, name: str) -> Self:
        self._table = name
        return self

    def where(self, condition: str) -> Self:
        self._conditions.append(condition)
        return self

    def limit(self, n: int) -> Self:
        self._limit = n
        return self

    def build(self) -> str:
        sql = f"SELECT * FROM {self._table}"
        if self._conditions:
            sql += " WHERE " + " AND ".join(self._conditions)
        if self._limit:
            sql += f" LIMIT {self._limit}"
        return sql

# Method chaining with correct types
query = (
    QueryBuilder()
    .table('users')
    .where('age > 18')
    .where('active = true')
    .limit(10)
    .build()
)
print(query)  # SELECT * FROM users WHERE age > 18 AND active = true LIMIT 10

# Self works correctly with inheritance
class AdvancedQueryBuilder(QueryBuilder):
    def join(self, table: str, on: str) -> Self:
        # Returns AdvancedQueryBuilder, not QueryBuilder!
        return self

