from typing import TypeVar, Generic, TypeAlias, ParamSpec, Callable
from functools import wraps

T_old = TypeVar('T_old')
def first_old(items: list[T_old]) -> T_old:
    return items[0]

class Stack_old(Generic[T_old]):
    def __init__(self) -> None:
        self._items: list[T_old] = []
    def push(self, item: T_old) -> None:
        self._items.append(item)
    def pop(self) -> T_old:
        return self._items.pop()

Vector_old: TypeAlias = list[float]

# --- New way (Python 3.12+) ---

# Generic function
def first[T](items: list[T]) -> T:
    """Return the first element, preserving type."""
    return items[0]

result = first([1, 2, 3])      # mypy infers: int
result = first(['a', 'b'])     # mypy infers: str

# Generic class
class Stack[T]:
    def __init__(self) -> None:
        self._items: list[T] = []

    def push(self, item: T) -> None:
        self._items.append(item)

    def pop(self) -> T:
        return self._items.pop()

    def peek(self) -> T:
        return self._items[-1]

    def __len__(self) -> int:
        return len(self._items)

int_stack = Stack[int]()
int_stack.push(42)
value: int = int_stack.pop()

# Type aliases
type Vector = list[float]
type Matrix = list[Vector]
type Callback[T] = Callable[[T], None]
type Result[T] = T | None

# Bounded type parameters
def max_item[T: (int, float)](items: list[T]) -> T:
    return max(items)

# Bound to a class
class Comparable:
    def __lt__(self, other): ...

def sort_items[T: Comparable](items: list[T]) -> list[T]:
    return sorted(items)

# Multiple type parameters
class Pair[T, U]:
    def __init__(self, first: T, second: U) -> None:
        self.first = first
        self.second = second

    def swap(self) -> 'Pair[U, T]':
        return Pair(self.second, self.first)

pair = Pair(1, 'hello')  # Pair[int, str]

# ParamSpec with new syntax
def logged[**P, R](func: Callable[P, R]) -> Callable[P, R]:
    @wraps(func)
    def wrapper(*args: P.args, **kwargs: P.kwargs) -> R:
        print(f"Calling {func.__name__}")
        return func(*args, **kwargs)
    return wrapper

@logged
def add(x: int, y: int) -> int:
    return x + y

