from datetime import datetime

# Basic inheritance
@dataclass
class Animal:
    name: str
    species: str

@dataclass
class Dog(Animal):
    breed: str
    trained: bool = False

dog = Dog(name='Rex', species='Canine', breed='Labrador')
print(dog)  # Dog(name='Rex', species='Canine', breed='Labrador', trained=False)

# Problem: parent with defaults + child without defaults
# @dataclass
# class Base:
#     x: int
#     y: int = 0  # Has default
#
# @dataclass
# class Child(Base):
#     z: int  # No default -> TypeError! (non-default after default)

# Solution 1: kw_only=True (Python 3.10+)
@dataclass(kw_only=True)
class Base:
    x: int
    y: int = 0

@dataclass(kw_only=True)
class Child(Base):
    z: int  # OK: keyword-only, no ordering issue

c = Child(x=1, z=3)  # y defaults to 0

# Solution 2: All child fields have defaults
@dataclass
class Base2:
    x: int
    y: int = 0

@dataclass
class Child2(Base2):
    z: int = 0  # Must have default since parent y has default

# __post_init__ chaining
@dataclass
class Timestamped:
    created_at: datetime = field(default_factory=datetime.utcnow, repr=False)
    updated_at: datetime = field(default_factory=datetime.utcnow, repr=False)

    def __post_init__(self):
        pass  # Base validation

@dataclass
class User(Timestamped):
    name: str = ''
    email: str = ''

    def __post_init__(self):
        super().__post_init__()  # Call parent's __post_init__
        if self.email and '@' not in self.email:
            raise ValueError(f"Invalid email: {self.email}")

user = User(name='Alice', email='alice@example.com')
print(user)  # User(name='Alice', email='alice@example.com')

# Mixin pattern with dataclasses
@dataclass
class Serializable:
    def to_dict(self) -> dict:
        from dataclasses import asdict
        return asdict(self)

    def to_json(self) -> str:
        import json
        return json.dumps(self.to_dict(), default=str)

@dataclass
class Validatable:
    def validate(self) -> list[str]:
        errors = []
        for f in fields(self):
            value = getattr(self, f.name)
            if value is None and f.default is not None:
                errors.append(f"{f.name} cannot be None")
        return errors

@dataclass
class Product(Serializable):
    name: str = ''
    price: float = 0.0
    tags: list[str] = field(default_factory=list)

p = Product('Widget', 9.99, ['sale'])
print(p.to_json())  # {"name": "Widget", "price": 9.99, "tags": ["sale"]}

# Abstract dataclass
from abc import ABC, abstractmethod

@dataclass
class Shape(ABC):
    color: str = 'black'

    @abstractmethod
    def area(self) -> float:
        ...

@dataclass
class Circle(Shape):
    radius: float = 0.0

    def area(self) -> float:
        return 3.14159 * self.radius ** 2

c = Circle(color='red', radius=5)
print(f"Area: {c.area():.2f}")  # Area: 78.54

